// Models/Review.cs
public class Review
{
    public int Id { get; set; }
    public string UserName { get; set; }
    public string ProductName { get; set; }
    public string Text { get; set; }
}

// Controllers/ProductController.cs
public class ProductController : Controller
{
    private readonly ApplicationDbContext _context;

    public ProductController(ApplicationDbContext context)
    {
        _context = context;
    }

    public async Task<IActionResult> ProductPage(string productName)
    {
        var product = await _context.Products.FirstOrDefaultAsync(p => p.Name == productName);
        if (product == null)
        {
            return NotFound();
        }

        var reviews = await _context.Reviews.Where(r => r.ProductName == productName).ToListAsync();
        return View(new ProductViewModel
        {
            Product = product,
            Reviews = reviews
        });
    }
}

// Views/Product/ProductPage.cshtml
@model ProductViewModel

<h1>@Model.Product.Name</h1>

<h2>Reviews:</h2>

@foreach (var review in Model.Reviews)
{
    <p><strong>@review.UserName:</strong></p>
    <p>@review.Text.Replace("\r\n", "<br />")</p>
}